    let stepSize = deltaDir.w;
    var samplePos = vec4f(start + dir * (stepSize * ran), stepSize * ran);
    let samplePosStart = samplePos;

    // Fast pass: skip until prob1 > easing threshold t0
    let t0 = paqdUni[0];
