// niivue brand mark shown in the top bar (see Menu.tsx).
//
// Inlined as a base64 data URI rather than a `*.png` import on purpose: every
// @niivue/react consumer must type-check and bundle this identically, but the
// PWA and the Streamlit frontend type-check this package *from source* and do
// not all provide an ambient `*.png` module declaration. A plain string sidesteps
// that entirely while still inlining (the asset is ~3.3 KB, well under any
// bundler's inline limit).
//
// Regenerate after the canonical master changes:
//   python -c "from PIL import Image; import base64,io; \n//     im=Image.open('apps/pwa/public/logo.png').convert('RGB').resize((96,96),Image.LANCZOS); \n//     b=io.BytesIO(); im.quantize(colors=128,method=Image.FASTOCTREE).save(b,'PNG',optimize=True); \n//     print('data:image/png;base64,'+base64.b64encode(b.getvalue()).decode())"
export const niivueLogo =
  'data:image/png;base64,'
